import os, json, re, datetime
from torch.utils.tensorboard import SummaryWriter

runs_dir = '/lixiang/project/huxing/Project_test/AgentSDKMetricSkill/rllm_train/output/runs'
tb_out = '/lixiang/project/huxing/Project_test/AgentSDKMetricSkill/rllm_train/output/tensorboard_from_logs'

converted = 0
skipped = 0
errors = []

for name in sorted(os.listdir(runs_dir)):
    run_path = os.path.join(runs_dir, name)
    if not os.path.isdir(run_path):
        continue

    tb_path = os.path.join(tb_out, name)
    if os.path.exists(tb_path):
        skipped += 1
        continue

    rt = None
    m = re.match(r'run_(\d{10})', name)
    if m:
        rt = datetime.datetime.fromtimestamp(int(m.group(1)))
    else:
        m2 = re.search(r'(\d{4})(\d{2})(\d{2})_(\d{2})(\d{2})', name)
        if m2:
            rt = datetime.datetime(int(m2.group(1)), int(m2.group(2)), int(m2.group(3)),
                                   int(m2.group(4)), int(m2.group(5)))
    if rt is None:
        cf = os.path.join(run_path, 'config.json')
        if os.path.exists(cf):
            rt = datetime.datetime.fromtimestamp(os.path.getmtime(cf))
        else:
            continue

    perf = os.path.join(run_path, 'perf_stats.json')
    training_log = os.path.join(run_path, 'training_log.txt')
    verl_metrics_path = os.path.join(run_path, 'verl_metrics.jsonl')

    rewards_by_step = {}

    # From perf_stats
    if os.path.exists(perf):
        with open(perf) as f:
            ps = json.load(f)
        for sr in ps.get('per_step_rollouts', []):
            rewards_by_step[sr['step']] = sr.get('avg_reward', 0)

    # From training_log (with encoding fallback)
    if os.path.exists(training_log):
        try:
            with open(training_log, encoding='utf-8', errors='replace') as f:
                lines = f.readlines()
        except:
            try:
                with open(training_log, encoding='latin-1') as f:
                    lines = f.readlines()
            except:
                lines = []

        step_trajs = {}
        current_step = None
        for line in lines:
            sm = re.search(r'step\s+(\d+)/\d+', line)
            if sm:
                current_step = int(sm.group(1))
                if current_step not in step_trajs:
                    step_trajs[current_step] = []
            tm = re.search(r'reward=([\d.]+)', line)
            if tm and current_step:
                step_trajs.setdefault(current_step, []).append(float(tm.group(1)))
        for step, rwds in step_trajs.items():
            if step not in rewards_by_step and rwds:
                rewards_by_step[step] = sum(rwds) / len(rwds)

    # From verl_metrics.jsonl
    verl_data = {}
    if os.path.exists(verl_metrics_path):
        with open(verl_metrics_path) as f:
            for line in f:
                try:
                    obj = json.loads(line.strip())
                    step = obj.get('step', obj.get('update_steps', 0))
                    verl_data[step] = obj
                except:
                    pass

    if not rewards_by_step and not verl_data:
        skipped += 1
        continue

    os.makedirs(tb_path, exist_ok=True)
    writer = SummaryWriter(log_dir=tb_path)

    for step in sorted(rewards_by_step.keys()):
        writer.add_scalar('trl/reward', rewards_by_step[step], global_step=step)

    for step in sorted(verl_data.keys()):
        obj = verl_data[step]
        for key in ['reward', 'loss', 'entropy', 'grad_norm', 'score', 'clipped_ratio']:
            if key in obj and isinstance(obj[key], (int, float)):
                writer.add_scalar(f'trl/{key}', float(obj[key]), global_step=step)

    writer.close()
    time_str = rt.strftime('%Y-%m-%d %H:%M')
    print(f"OK  {time_str}  {name}  (reward:{len(rewards_by_step)} verl:{len(verl_data)})")
    converted += 1

print(f"\nConverted: {converted}, Skipped/Existed: {skipped}")
PYEOF

